import re

def parse_interfaces(config: str) -> list:
    interfaces = []
    current = None
    for line in config.split('\n'):
        iface_match = re.match(r'^interface\s+(\S+)', line)
        if iface_match:
            if current:
                interfaces.append(current)
            name = iface_match.group(1)
            vlan_match = re.match(r'Vlan(\d+)', name)
            current = {
                'name': name,
                'ip_address': None,
                'subnet_mask': None,
                'description': '',
                'shutdown': False,
                'vlan': int(vlan_match.group(1)) if vlan_match else None,
            }
        elif current:
            ip_match = re.match(r'\s+ip address\s+(\S+)\s+(\S+)', line)
            desc_match = re.match(r'\s+description\s+(.+)', line)
            if ip_match:
                current['ip_address'] = ip_match.group(1)
                current['subnet_mask'] = ip_match.group(2)
            elif desc_match:
                current['description'] = desc_match.group(1).strip()
            elif re.match(r'\s+shutdown', line):
                current['shutdown'] = True
    if current:
        interfaces.append(current)
    return interfaces

def find_default_gateway(config: str) -> str:
    match = re.search(r'ip route\s+0\.0\.0\.0\s+0\.0\.0\.0\s+(\S+)', config)
    return match.group(1) if match else 'not configured'
